INSERT INTO `audit_ai_finding` VALUES (26,16,'内容缺失','报告正文无法获取','待审阅报告正文内容为\'Request failed with status code 404\'，无法获取有效报告内容进行审阅。 位置：待审阅报告正文。建议：请确保报告文件可正常访问并提供完整、有效的正文内容。',1),(27,16,'标准不符','无法核对审核依据','因报告正文缺失或不可读，无法对照审核依据核对具体内容，所有应包含的章节、数据、结论等均视为不符合审核要求。 位置：整体报告内容。建议：在提供有效报告内容后，需逐项对照审核依据文档中的技术规范、格式要求及内容条款进行合规性检查。',2),(35,30,'标准不符','生产地址与知识库记录不一致','报告片段中显示的生产地址为“宁夏回族自治区银川市金凤区宁安南大街 490 号 IBI 育成中心二期 3 号楼二层 205-2 室”，而知识库搜索结果（kb_chunk_id: 3）中记录的同单位生产地址为“河北省秦皇岛市经济技术开发区珠江道 123456 号”，两者存在明显冲突。 位置：报告基本信息表 - 生产地址字段。建议：核实生产单位实际注册地址或生产场所，修正报告中的生产地址以保持一致性。',1),(36,30,'标准不符','检验依据缺少 GB/T 3836.2-2021','报告片段中列出的检验依据仅包含 GB/T 3836.1-2021 和 GB/T 3836.4-2021，但根据产品说明书（执行标准），该产品为\"矿用隔爆兼本安型\"，必须同时执行 GB/T 3836.2-2021《爆炸性环境 第 2 部分：由隔爆外壳\"d\"保护的设备》，报告中缺失该关键标准。 位置：检验依据章节。建议：在检验依据中补充 GB/T 3836.2-2021。',2),(37,30,'内容缺失','签发日期未填写','报告结论下方的\"签发日期\"字段显示为\"年    月    日\"，未填写具体日期，不符合检验报告完整性要求。 位置：检验结论章节末尾。建议：填写具体的签发日期。',3),(38,30,'内容缺失','签字人员信息缺失','报告中的\"批准\"、\"审核\"、\"主检\"栏目均为空白，仅有\"电子签\"字样但未显示具体签名或印章，不符合\"报告无主检、审核、批准人签字（章）无效\"的规定。 位置：检验结论下方签字栏。建议：补充完整的批准、审核、主检人员签字或电子签章。',4),(39,30,'标准不符','以太网传输协议表述错误','报告片段中虽未直接列出以太网参数，但依据同批次知识库搜索结果（产品说明书），该设备以太网传输方式标注为\"TPC/IP\"，而标准通用术语应为\"TCP/IP\"，存在拼写错误导致的技术表述不符。 位置：知识库搜索结果 kb_chunk_id:2 第 3.2.5 条 b 款。建议：将\"TPC/IP\"修改为标准的\"TCP/IP\"。',5),(40,30,'内容缺失','外壳材质描述与说明书不一致','报告片段 7.4.1 条款中描述外壳材质为\"ABS\"，而知识库搜索结果显示该产品（KXJ127 矿用隔爆兼本安型 PLC 控制箱）说明书第 2.3 条明确记载外壳材料为\"Q235B\"，两者存在明显矛盾。 位置：报告片段 4，章节 7.4.1 适用性。建议：请依据知识库审核依据修正相关内容。',6),(41,30,'数据异常','电池额定电压描述与标准参数不一致','报告片段第 23.5 条描述电池额定电压为 3.7V，而知识库搜索结果显示该设备本安电源输出接口额定输出电压为 DC12V，本安参数电源端 Uo 为 DC12.5V，两者数值存在显著差异，需核实是否为同一电池组或描述错误。 位置：报告片段第 23.5 条 电池额定值。建议：核对产品实际电池规格与本安参数设计值，修正报告中的电压数值或补充说明差异原因。',7),(42,30,'标准不符','防爆标志表述不一致','报告片段 29.4 条款中记录的爆炸性气体环境防爆标志为\"Ex ib Ⅰ Mb\"，而知识库搜索结果（产品说明书）第 2.2 节明确规定的防爆标志为\"Ex db [ib Mb]ⅠMb\"。该产品为隔爆兼本安型设备，报告中遗漏了隔爆型式\"db\"及本安型式的括号标注，与产品实际认证标志不符。 位置：报告片段 8，章节 29.4 爆炸性气体环境防爆标志。建议：将防爆标志修改为与产品说明书及认证一致的内容：Ex db [ib Mb]ⅠMb。',8),(43,30,'标准不符','电缆引入装置密封圈适用外径范围与报告结论不一致','待审阅报告中判定\'Ⅰ类设备的外壳\'及\'符合表 5 要求的设备\'为合格（P），暗示结构符合标准要求。但依据知识库搜索结果（说明书第 4 部分），该设备 M22 引入装置密封圈适用的电缆外径范围为Ø9.0 ~ Ø10.0，范围过窄，可能无法满足 GB/T 3836.1 或 GB/T 3836.2 中关于电缆引入装置应能适配标准规定范围内多种电缆外径的要求，存在结构合规性风险。 位置：报告片段第 10 页，章节 6.1.2.1 及 6.1.2.2。建议：核实电缆引入装置密封圈的实际适用范围是否满足相关防爆标准对电缆外径适应性的要求，如不满足需整改并重新评估结论。',9),(44,30,'数据异常','报告编号不一致','待审阅报告片段中出现的报告编号为\"№：201854833\"，而知识库搜索结果中明确显示的当前检验报告编号为\"№：2025520398FB\"，两者不一致，存在引用错误或版本混淆。 位置：第 16 页 共 22 页，报告编号字段。建议：核实并统一报告编号，确保全文使用正确的报告编号\"№：2025520398FB\"。',10),(45,30,'标准不符','生产单位地址信息冲突','待审阅报告片段中显示的生产单位地址为\"河北省秦皇岛市经济技术开发区珠江道 123456 号\"，而知识库搜索结果中显示的检验机构地址为\"中国 北京市北京经济技术开发区（大兴）采育镇育隆大街 5 号\"，且该机构名称为\"煤科（北京）检测技术有限公司\"，地址信息与机构名称及备案信息不符。 位置：第 9 页 共 11 页，生产单位地址字段。建议：修正生产单位地址，确保与机构注册信息及知识库中的备案地址一致。',11),(46,30,'标准不符','外壳材质与说明书描述不一致','报告片段中描述外壳材质为\"ABS\"，而知识库搜索结果中的产品说明书（KXJ127 矿用隔爆兼本安型 PLC 控制箱）第 2.3 条明确规定外壳材料为\"Q235B\"，两者表述不一致。 位置：报告片段第 15 页，外壳材质描述项。建议：核实产品实际外壳材质，若为 Q235B 则修改报告为\"Q235B\"，若确为 ABS 需确认是否对应正确型号并提供依据。',12);
